uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    vec3 main = texture( sampler_main, vUv ).xyz;
    vec3 mblur = GetBlur1( vUv );
    main = ( (main-mblur*.5)*3 );
    float zoom = 1+.5*( (q9*vUvOriginal.y-q8*vUvOriginal.x)*6+vRadius*sin(vAngle+2-q3-q4)*mblur.z*3)*(.01+(q1-q2)*.01);
    float rot = (mblur.y-mblur.x)*(q7-q8)*.5;
    vec2 zcr = vec2(.5,.5);
    vec2 cr = vec2(.5,.5);
    vec2 newuv = vUv;

    ///////////////////rotation////////////////
    newuv = vUv - cr;
    float s = sin(rot);
    float c = cos(rot);
    newuv = vec2( (vUv.x-cr.x)*c-(vUv.y-cr.y)*s , (vUv.x-cr.x)*s+(vUv.y-cr.y)*c  );
    newuv = newuv + cr;
    ///////////////////rotation////////////////

    ///////////////////zoom////////////////
    newuv = newuv-zcr;
    newuv = newuv * zoom;
    newuv= newuv+zcr;
    ///////////////////zoom////////////////


    vec3 colorwarp = texture( sampler_main, newuv );

    vec3 color = texture(sampler_rand02, newuv ).xyz;
//    ret = ( (  (colorwarp*main*3-normalize(color)) ) );
    ret= mix(colorwarp,main*color,1-sin((color-colorwarp)*6));
    // darken (decay) over uTime
    ret *= 0.96; //or try: ret -= 0.004;


  fragColor = ret;
